import React, { useState } from 'react';
import API from '../api/axios';
import { useNavigate } from 'react-router-dom';

const Login = () => {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();

    const handleLogin = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            const { data } = await API.post('/auth/login', { email, password });
            localStorage.setItem('token', data.token);
            localStorage.setItem('role', data.role);
            localStorage.setItem('userName', data.email || 'User');
            navigate('/dashboard');
        } catch (err) {
            alert(err.response?.data?.message || "Invalid email or password");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={styles.loginPage}>
            <style>{`
                @import url('https://fonts.googleapis.com/css2?family=Poppins:wght@300;400;600;700;800&display=swap');

                .login-page-wrapper * {
                    font-family: 'Poppins', sans-serif;
                }

                .animated-bg {
                    position: absolute;
                    top: 0;
                    left: 0;
                    width: 100%;
                    height: 100%;
                    z-index: 1;
                    overflow: hidden;
                }

                .orb {
                    position: absolute;
                    border-radius: 50%;
                    opacity: 0.1;
                }

                .orb-1 {
                    width: 400px;
                    height: 400px;
                    background: linear-gradient(135deg, #38bdf8, #818cf8);
                    top: -200px;
                    right: -200px;
                    animation: float 20s ease-in-out infinite;
                }

                .orb-2 {
                    width: 300px;
                    height: 300px;
                    background: linear-gradient(135deg, #818cf8, #38bdf8);
                    bottom: -150px;
                    left: -150px;
                    animation: float 25s ease-in-out infinite reverse;
                }

                @keyframes float {
                    0%, 100% {
                        transform: translate(0, 0);
                    }
                    25% {
                        transform: translate(30px, -30px);
                    }
                    50% {
                        transform: translate(-30px, 30px);
                    }
                    75% {
                        transform: translate(-30px, -30px);
                    }
                }

                .login-card-container {
                    z-index: 2;
                    background: linear-gradient(135deg, rgba(30, 41, 59, 0.7), rgba(30, 41, 59, 0.5));
                    backdrop-filter: blur(20px);
                    border: 2px solid rgba(56, 189, 248, 0.2);
                    padding: 50px 45px;
                    border-radius: 24px;
                    width: 100%;
                    max-width: 460px;
                    box-shadow: 0 25px 60px -15px rgba(56, 189, 248, 0.3);
                    text-align: center;
                    animation: slideUp 0.5s ease;
                }

                @keyframes slideUp {
                    from {
                        opacity: 0;
                        transform: translateY(30px);
                    }
                    to {
                        opacity: 1;
                        transform: translateY(0);
                    }
                }

                .login-header {
                    margin-bottom: 40px;
                }

                .login-title {
                    font-size: 3rem;
                    font-weight: 800;
                    background: linear-gradient(135deg, #38bdf8, #818cf8);
                    -webkit-background-clip: text;
                    -webkit-text-fill-color: transparent;
                    background-clip: text;
                    margin-bottom: 12px;
                    letter-spacing: -1px;
                    text-transform: uppercase;
                }

                .login-subtitle {
                    color: #94a3b8;
                    font-size: 0.95rem;
                    font-weight: 500;
                    letter-spacing: 1px;
                }

                .form-container {
                    display: flex;
                    flex-direction: column;
                    gap: 22px;
                    margin-bottom: 30px;
                }

                .login-form-group {
                    display: flex;
                    flex-direction: column;
                    text-align: left;
                }

                .login-form-group label {
                    display: block;
                    color: #cbd5e1;
                    margin-bottom: 10px;
                    font-size: 0.9rem;
                    font-weight: 600;
                    letter-spacing: 0.5px;
                    text-transform: uppercase;
                }

                .login-form-group input {
                    width: 100%;
                    padding: 14px 16px;
                    background: rgba(20, 28, 45, 0.6);
                    border: 2px solid rgba(51, 65, 85, 0.4);
                    border-radius: 12px;
                    color: #fff;
                    font-size: 0.95rem;
                    font-family: 'Poppins', sans-serif;
                    transition: all 0.3s ease;
                    box-sizing: border-box;
                }

                .login-form-group input:hover {
                    border-color: rgba(56, 189, 248, 0.3);
                    background: rgba(20, 28, 45, 0.8);
                }

                .login-form-group input:focus {
                    outline: none;
                    border-color: #38bdf8;
                    background: rgba(20, 28, 45, 0.9);
                    box-shadow: 0 0 0 3px rgba(56, 189, 248, 0.15);
                }

                .login-form-group input::placeholder {
                    color: #64748b;
                }

                .login-submit-btn {
                    padding: 14px 24px;
                    background: linear-gradient(135deg, #38bdf8, #818cf8);
                    border: none;
                    border-radius: 12px;
                    color: white;
                    font-size: 0.95rem;
                    font-weight: 700;
                    cursor: pointer;
                    transition: all 0.3s ease;
                    font-family: 'Poppins', sans-serif;
                    text-transform: uppercase;
                    letter-spacing: 1px;
                    box-shadow: 0 10px 30px -8px rgba(56, 189, 248, 0.4);
                    margin-top: 10px;
                }

                .login-submit-btn:hover:not(:disabled) {
                    transform: translateY(-3px);
                    box-shadow: 0 15px 40px -10px rgba(56, 189, 248, 0.6);
                }

                .login-submit-btn:active:not(:disabled) {
                    transform: translateY(-1px);
                }

                .login-submit-btn:disabled {
                    opacity: 0.6;
                    cursor: not-allowed;
                }

                .login-footer {
                    margin-top: 35px;
                    padding-top: 25px;
                    border-top: 2px solid rgba(51, 65, 85, 0.3);
                    color: #64748b;
                    font-size: 0.75rem;
                    font-weight: 600;
                    letter-spacing: 1px;
                    text-transform: uppercase;
                }
            `}</style>

            {/* Animated Background */}
            <div className="animated-bg">
                <div className="orb orb-1"></div>
                <div className="orb orb-2"></div>
            </div>

            {/* Login Card */}
            <div className="login-card-container login-page-wrapper">
                <div className="login-header">
                    <div className="login-title">🎯 TMS</div>
                    <div className="login-subtitle">Ticket Management System</div>
                </div>

                <form onSubmit={handleLogin} className="form-container">
                    <div className="login-form-group">
                        <label htmlFor="email">📧 Email Address</label>
                        <input 
                            id="email"
                            type="email" 
                            placeholder="name@company.com" 
                            value={email}
                            onChange={e => setEmail(e.target.value)} 
                            required 
                        />
                    </div>

                    <div className="login-form-group">
                        <label htmlFor="password">🔐 Password</label>
                        <input 
                            id="password"
                            type="password" 
                            placeholder="••••••••" 
                            value={password}
                            onChange={e => setPassword(e.target.value)} 
                            required 
                        />
                    </div>

                    <button type="submit" className="login-submit-btn" disabled={loading}>
                        {loading ? '⏳ Validating Access...' : '🚀 Sign In'}
                    </button>
                </form>

                <div className="login-footer">
                    ✓ Secure Encrypted Access Only
                </div>
            </div>
        </div>
    );
};

const styles = {
    loginPage: {
        height: '100vh',
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        background: 'linear-gradient(135deg, #0f172a 0%, #1a1f35 50%, #0f172a 100%)',
        overflow: 'hidden',
        position: 'relative',
    },
};

export default Login;
